+    let ls = lstsq(&a, &b, LstsqOptions::default()).expect("lstsq");
+    assert_eq!(ls.x.len(), 2);
+
+    let pi = pinv(&a, PinvOptions::default()).expect("pinv");
+    // pinv(A) * b should give similar result to lstsq
+    let mut pinv_x = vec![0.0; 2];
+    for i in 0..2 {
